#include <string.h>

typedef struct {
    int x;
    int y;
    char label[16];
} Marker;

Marker make_marker(int x, int y, const char *label) {
    Marker m = {0};
    m.x = x;
    m.y = y;
    strncpy(m.label, label, sizeof(m.label) - 1);
    m.label[sizeof(m.label) - 1] = '\0';
    return m;
}

int main(void) {
    Marker a = make_marker(10, 20, "Alpha");
    Marker b = ____;
    printf("a = (%d, %d, %s)\n", a.x, a.y, a.label);
    printf("b = (%d, %d, %s)\n", b.x, b.y, b.label);
    printf("Egaux (memcmp) : %d\n", memcmp(&a, &b, sizeof(Marker)) == 0);

    b.____ = 99;
    strncpy(b.____, "Beta", sizeof(b.label) - 1);
    printf("Apres modif b:\n");
    printf("a = (%d, %d, %s)\n", a.x, a.y, a.label);
    printf("b = (%d, %d, %s)\n", b.x, b.y, b.label);
    printf("Egaux (memcmp) : %d\n", memcmp(&a, &b, sizeof(Marker)) == 0);
    return 0;
}

